// ══════════════════════════════════════════════════════════════
//  Education Cloud — Domains and Components
//  14 domains covering the complete learner lifecycle
// ══════════════════════════════════════════════════════════════

export const PRODUCT = {

recruitment: {
  packages: ['educationcloud'],
  name: "Recruitment",
  icon: "\u{1F4E3}",
  color: "#3b82f6",
  description: "Manages the top of the enrollment funnel, from first inquiry to application-ready prospect. Recruitment captures leads from campus events, website inquiries, and partner referrals, then nurtures them through targeted campaigns and personalized outreach. AI-powered recruitment agents automate communication sequences and surface high-intent prospects for admissions counselors.",
  components: [
    {id:"prospect-management",name:"Prospect Management",icon:"\u{1F465}",desc:"Captures and tracks prospective students from initial inquiry through application readiness. Each prospect record stores academic interests, demographic information, communication preferences, and engagement history. Lead scoring models identify prospects most likely to apply based on interaction patterns and qualification criteria, while the Scoring Framework provides predictions about the likelihood of a prospective learner enrolling.",tags:["Lead","ContactProfile"],docs:["Education Cloud uses the lead and person account objects to record suspect and prospect information. When a prospect signals interest in your institution, a person account is created with their details so that the recruiting team can better engage with the potential student. Suspects who have not yet indicated interest are tracked as leads, and when they express interest, they are automatically converted to person accounts through lead conversion.","Inquiry management flows help learners sign up for communications, ask questions, and request to be contacted. The platform provides several screen flows including Sign Up for Information, Connect With Us, and Submit an Inquiry Form, each creating the appropriate records and associations. These flows can be embedded into the Education Portal or a third-party website using Lightning Out.","Scoring Framework uses CRM Analytics to predict the likelihood of a prospective learner enrolling based on their current level of engagement. By knowing which prospects are most likely interested, the admissions team can focus outreach efforts on those learners to improve admission rates. Territory management and actionable lists further help recruiters prioritize and manage prospect portfolios efficiently."],docUrl:"https://developer.salesforce.com/docs/platform/data-models/guide/recruitment-and-admissions.html",connections:[{planet:"admissions",desc:"Qualified prospects submit applications"},{planet:"records",desc:"Prospect data flows into person records"}]},
    {id:"campaign-management",name:"Campaign Management",icon:"\u{1F4E8}",desc:"Orchestrates multi-channel recruitment campaigns targeting specific student populations. Campaigns track open houses, campus visits, virtual events, email sequences, and social media outreach. Campaign members are tracked through response stages to measure yield and conversion rates across recruitment activities, with actionable lists enabling targeted marketing assignments.",tags:["Campaign","CampaignMember"],docs:["The Recruitment and Admissions app enables admissions officers and recruiters to stay on top of their tasks while monitoring the overall health of the admissions pipeline in real time. Actionable Lists allow directors to create prospect lists from multiple objects, collaborate with staff, and take action within the list. These lists can be assigned to recruiters for targeted follow-up based on specific criteria such as geography, academic interest, or engagement level.","Marketing Cloud Engagement for Education synchronizes your Education Cloud CRM data with Marketing Cloud to create email campaigns. Use cases include application deadline reminders, recruiting appointment details, class year and fundraising campaigns, and alumni outreach. Interest tags help identify key interests, preferences, and needs to deepen connections between recruiters and prospects.","Opportunity management features allow institutions to forecast and track enrollment pipeline by creating opportunities from academic interests. When a prospect selects a learning program in the Sign Up for Information form, the system can automatically generate an opportunity record, enabling data-driven enrollment projections tied to specific terms and programs."],connections:[{planet:"analytics",desc:"Campaign metrics feed recruitment dashboards"}]},
    {id:"recruitment-events",name:"Recruitment Events",icon:"\u{1F3AA}",desc:"Manages campus tours, open houses, information sessions, and virtual recruitment events. Event registration captures attendee details and interests, and post-event follow-up workflows automatically engage attendees based on their level of interest. The Student Recruitment Agent can assist prospective students in registering for campus tours, visits, and events through conversational AI.",tags:["Campaign","CampaignMember"],docs:["Campus and Program Finder makes information about your campus, learning programs, and support programs publicly searchable on your Experience Cloud site. It helps applicants, students, and families browse and search for campuses, schools, and programs in their area. They can filter by learning program, campus or school, grade level, and other criteria, with search results presented in a list or on a map.","The Student Recruitment Agent includes a Campus Tours, Visits, and Events Registration topic that assists users in registering for campus tours, campus visits, or campus events. The agent uses the Create Campus Tour Registration and Get Campus Tour Campaigns actions to streamline the registration process for both authenticated and unauthenticated users.","Education Cloud provides flow templates to help manage recruitment events, including the ability to create campaign sharing rules for campus tours and configure event-specific record types. The Recruitment and Admissions Consoles give staff a single home page view to track progress toward goals with variety of KPI reports and manage recruitment event logistics."],connections:[{planet:"experience",desc:"Event registration through the prospect portal"}]},
    {id:"recruitment-communications",name:"Recruitment Communications",icon:"\u{1F4EC}",desc:"Manages outbound communications to prospective students across email, SMS, and direct mail channels. Communication templates are personalized with prospect data and academic program details. Marketing Cloud Engagement for Education synchronizes CRM data with Marketing Cloud to create targeted email campaigns for application reminders, recruiting details, and alumni outreach.",tags:["ContactPointEmail","ContactPointPhone"],docs:["Education Cloud's inquiry management flows provide multiple channels for prospects to engage with your institution. The Sign Up for Information flow processes requests to receive regular updates and can enroll prospects in Marketing Cloud journeys using Marketing Cloud Connect. The Connect With Us flow creates contact request records linking prospects with staff, while the Submit an Inquiry Form flow creates case records for detailed questions.","Flexcards for inquiry flows provide a variety of ways for prospects, applicants, and students to engage with your institution through the Education Portal. These components can be cloned and customized to suit the purpose of each flow, with display labels and text tailored to your institution's branding and messaging strategy. Inquiry flows can also be embedded into third-party websites using Lightning Out.","Interest Tags help identify key interests, preferences, and needs of prospects, deepening the connection between recruiters and prospective students by speaking a common language. Use cases include identifying interests such as which sports prospects play or tracking specific academic or extracurricular interests during the recruitment process."],connections:[{planet:"agentforce",desc:"Recruitment agent automates outreach sequences"}]},
    {id:"territory-management",name:"Territory Management",icon:"\u{1F5FA}",desc:"Assigns recruitment counselors to geographic territories, feeder schools, and prospect segments. Territory rules ensure equitable distribution of prospects among counselors and automatic routing of new inquiries to the appropriate recruiter. Business Rules Engine can route prospects to the right counselor based on attributes from their interests form.",tags:["Lead"],docs:["Actionable List Engagement, Actionable Segmentation, and Actionable List Member allow directors to create lists from multiple objects, collaborate with other staff, and take action within the list. Use cases include prioritizing applicants, creating lists of students based on specific criteria, creating portfolios of prospects for relationship officers, and curating lists of VIP parents to call based on defined criteria.","The Business Rules Engine enables institutions to execute business logic at scale without code. Standard use cases include routing prospects to the right counselor based on attributes, routing learners to the right staff member for application follow-up, and determining scholarship eligibility. Business users can change rules, such as adjusting GPA requirements, without modifying the underlying automation.","The Recruitment and Admissions app provides a home page for recruiters where they can create and manage appointments with students, respond to and manage prospective student requests for information, and track progress toward recruitment goals. Directors can create actionable lists of prospects and assign them to recruiters for targeted outreach."],connections:[{planet:"analytics",desc:"Territory performance feeds recruitment analytics"}]}
  ],
  dataFlow:["Prospect submits inquiry or attends recruitment event","Lead record is created and assigned to a recruitment counselor","Counselor nurtures prospect through targeted campaigns","AI recruitment agent automates personalized outreach","Qualified prospect proceeds to formal application submission"],
  connections:[{planet:"admissions",desc:"Qualified prospects move to applications"},{planet:"records",desc:"Prospect data creates person records"},{planet:"agentforce",desc:"AI recruitment agent automates outreach"},{planet:"experience",desc:"Prospect portal for inquiry and events"},{planet:"analytics",desc:"Recruitment funnel dashboards"}]
},

admissions: {
  packages: ['educationcloud'],
  name: "Admissions",
  icon: "\u{1F4CB}",
  color: "#6366f1",
  description: "Handles the full application lifecycle from submission through document collection, review, and admission decisions. Admissions supports multiple application types including undergraduate, graduate, transfer, and international applications. Configurable review workflows route applications through committee evaluation with scoring rubrics, and automated notifications keep applicants informed at every stage.",
  components: [
    {id:"application-management",name:"Application Management",icon:"\u{1F4C4}",desc:"Manages the creation, submission, and lifecycle of student applications. Education Cloud provides a flexible application experience supporting single-stage applications completed all at once and multiple-stage applications completed over time. Not only can students submit applications for themselves, third parties such as parents, guardians, or agents can submit applications on behalf of a student.",tags:["IndividualApplication","Applicant"],docs:["Education Cloud uses OmniStudio components to create customizable application forms. When an applicant registers on the learner portal, Education Cloud automatically creates a person account for them. The platform supports multiple application types with configurable stages, and applications progress through statuses from draft through submitted, under review, and decision rendered. Multi-cycle support allows the same applicant to apply across different programs or terms.","Application management uses multiple objects to model an applicant's information. The Individual Application record tracks the application itself, the Applicant record links it to a person account, the Preliminary Application Reference stores in-progress applications, and Document Checklist Items track required materials. Education Cloud provides flow templates to automatically create a case for an applicant and assign it to the appropriate support staff.","Data Importer for Common App uses Data Processing Engine to transform and save Common App First-Year data as new or updated records in Education Cloud. The integration tool groups objects into processing engine definitions that run sequentially to transform and integrate the data, enabling institutions to import standard applicant, suspect, prospect, and recommender data into applicable Education Cloud objects."],docUrl:"https://developer.salesforce.com/docs/platform/data-models/guide/recruitment-and-admissions.html",connections:[{planet:"recruitment",desc:"Applications originate from recruited prospects"},{planet:"enrollment",desc:"Admitted students proceed to enrollment"}]},
    {id:"document-tracking",name:"Document Tracking",icon:"\u{1F4CE}",desc:"Manages the collection and verification of required application documents including transcripts, test scores, recommendation letters, essays, and financial documents. Checklist items track which documents have been received, verified, or are still outstanding. Intelligent Document Reader can automatically extract and process information from uploaded documents to speed intake.",tags:["DocumentChecklistItem"],docs:["Education Cloud provides multiple components for managing documents including Document Checklist for tracking required materials, Document Generation for creating standardized correspondence, and Intelligent Document Reader for automated document processing. These tools reduce friction and streamline updates between students and staff by enabling real-time document uploading and automated document management processes.","Each document checklist item represents a specific document type such as transcripts, test scores, essays, or recommendation letters. Status tracking shows whether each document has been received, is under review, or is still outstanding. The recommender experience simplifies the recommendation process from sending a survey invitation to populating the application task with recommendation details and enabling reminders.","When an applicant uploads a document such as a college application essay, a Document Checklist Item record is created and associated with their application. Bulk document processing handles high-volume intake periods, and automated reminders help ensure applicants submit all required materials before deadlines."],connections:[]},
    {id:"application-review",name:"Application Review",icon:"\u{1F50D}",desc:"Routes applications through structured review workflows with configurable reviewer assignments, scoring rubrics, and decision criteria. Multiple reviewers can evaluate the same application independently, and committee reviews aggregate individual scores into a consensus recommendation. OmniStudio enables dynamic scoring rubrics that speed up the admissions evaluation process.",tags:["IndividualApplication"],docs:["The Reviewer Console is designed specifically for people who conduct application reviews. Reviewers can be anyone in your institution or external partners, and they receive the Education Cloud Limited Access permission set license giving them access to the elements needed to view and approve applications. The console shows a list of assigned applications, tasks due today, and upcoming events.","Review workflows can be automated using Education Cloud's flow capabilities. The platform provides flow templates for automating the application review process, including case creation and assignment when applications are submitted. Decision tables from the Business Rules Engine can be used to apply complex evaluation criteria and scoring logic at scale without custom code.","The Admissions Console gives admissions officers a home page view showing application volume, status of application reviews, admission efficiency, incomplete applications, and applications ready for a decision. List views allow quick filtering between applications that are ready for decision, incomplete applications, and those assigned for review, with the ability to update statuses and assign reviewers directly from the console."],connections:[]},
    {id:"admissions-decisions",name:"Admissions Decisions",icon:"\u{2705}",desc:"Records and communicates admission decisions including accept, deny, waitlist, and conditional admission. Application decision records are automatically shared with portal users on the decision release date you define on the application timeline, supporting both rolling admissions and batch release. Conditional offers specify requirements that must be met before enrollment, such as final transcript submission or minimum GPA maintenance.",tags:["IndividualApplication","Applicant"],docs:["Application decision records represent the publicly released decision for an application to an institution. These records are automatically shared with Experience Cloud users on the decision release date and early application release date defined on the application timeline object. If no decision release date is entered, records are not shared with portal users, and if the date is in the past, records are shared immediately.","For rolling admissions decisions, institutions can enter the same values in the Application Open Date and Decision Release Date fields, which shares decision records as soon as they are created within the application time frame. Institutions should test the performance of their Experience Cloud site to account for high-traffic situations such as sharing application decisions on a specific day or time.","Education Cloud also provides automated flows to close cases when an application is rejected, canceled, or when the applicant enrolls. The Academic Term Enrollment object represents the academic term that the applicant enrolls in, connecting the admission decision to the student's subsequent enrollment record and financial aid packaging."],connections:[{planet:"financials",desc:"Admission triggers financial aid packaging"}]},
    {id:"preliminary-applications",name:"Preliminary Applications",icon:"\u{1F4DD}",desc:"Supports early-stage or simplified application forms that capture initial interest before a full application is required. Preliminary application reference records store applications that are in progress so that applicants can finish at a later time. These lightweight records help institutions gauge demand for programs and begin building relationships with prospective students before the formal application window opens.",tags:["PreliminaryApplication"],docs:["Preliminary Application Reference records store applications that are in progress, allowing applicants to start an application and return to complete it later. This supports multi-stage application workflows where different sections can be completed at different times. For example, an applicant might submit basic personal information today and come back a week later to enter their educational history, without needing to complete stages in a linear order.","The Student Recruitment Agent can help prospective students start applications through the Admissions Application topic, which creates application records and walks prospects through the process conversationally. The agent can access academic term data, learning program data, and program term application timeline data to provide context-aware guidance during the application process."],connections:[{planet:"recruitment",desc:"Preliminary apps bridge recruitment and admissions"}]},
    {id:"admissions-console",name:"Admissions Console",icon:"\u{1F5A5}",desc:"A purpose-built staff workspace that surfaces the most important admissions data in a single view. The console displays application queues, review assignments, decision summaries, and key metrics like application volume and yield rates. Education Cloud provides separate consoles for admissions officers, recruiters, directors, and application reviewers, each tailored to their specific role and access level.",tags:["IndividualApplication"],docs:["The Admissions Console is built using Lightning App Builder and includes an Education Analytics Dashboard component showing Recruitment and Admissions Insights, tabbed list views for applications ready for decision and assigned reviews, a Today's Tasks component, and an upcoming events list. The console can be customized to suit the requirements of your institution with role-specific layouts.","Education Cloud has separate consoles for the admissions officer and application reviewer. The Admissions Console gives officers the broadest access with application volume, status of reviews, admission efficiency, incomplete applications, and applications ready for decision. The Reviewer Console provides a focused view of assigned applications, daily tasks, and upcoming events for users with the Limited Access permission set.","The Director Console for Recruitment and Admissions allows a director to see admissions and recruitment analytics, create actionable lists and assign them to staff. The Recruiter Console provides a home page for the Recruitment and Admissions app specifically designed for recruiters, enabling them to manage prospect outreach and event coordination."],connections:[{planet:"agentforce",desc:"Admissions agent answers applicant questions"}]}
  ],
  dataFlow:["Applicant submits application with required documents","Document checklist tracks receipt and verification of materials","Application is routed to reviewers based on program and criteria","Reviewers score and recommend using structured rubrics","Admissions committee renders final decision","Decision is communicated and applicant responds with intent to enroll"],
  connections:[{planet:"recruitment",desc:"Applications originate from recruited prospects"},{planet:"records",desc:"Applicant data stored on person records"},{planet:"enrollment",desc:"Admitted students enroll in programs"},{planet:"financials",desc:"Application fees and financial aid packaging"},{planet:"agentforce",desc:"AI agent answers applicant questions"},{planet:"experience",desc:"Applicant portal for status tracking"}]
},

academics: {
  packages: ['educationcloud'],
  name: "Academic Operations",
  icon: "\u{1F3EB}",
  color: "#8b5cf6",
  description: "The structural backbone that defines what an institution offers: programs, courses, academic terms, and learning objectives. Academic Operations manages the course catalog, schedules offerings across terms, and establishes the credit equivalency mappings that enable transfer credit evaluation. Faculty and teaching assistant assignments link instructors to specific course offerings.",
  components: [
    {id:"program-management",name:"Program Management",icon:"\u{1F393}",desc:"Defines degree programs, certificates, and academic pathways with their requirements, credit thresholds, and learning outcomes. Learning programs track the structure, administration, and enrollment and completion requirements for your offerings. Program Plan Builder enables administrators to create, manage, and visualize the sequence of requirements that students must fulfill to earn a credential.",tags:["Program"],docs:["Learning programs can be degree or credential programs, academic support programs, recreational programs, or continuing education. Education Cloud uses the same architectural building blocks to model each of them, with Learning representing the curriculum, Learning Achievement capturing the outcome, and Learning Program Plan detailing the specific requirements for a given catalog year. When the institution finalizes its catalog for the next academic year, changed requirements are captured in a new program plan record.","The Program Plan Builder flow allows administrators to create and visualize program plans that define the set of requirements in effect at a given time. Program plan requirements represent specific items such as required courses, thesis work, or internships. To help organize programs, institutions are encouraged to create accounts for each department or college, then assign records to the appropriate account.","Advanced Academic Operations extends the power of Education Cloud with AI-powered student information system capabilities, improving the student and staff experience by streamlining and automating processes from course registration to curriculum management. This add-on requires the Education Cloud Advanced Academic Operations for Experience Cloud license and provides additional features for managing learning pathways and intelligent degree planning."],docUrl:"https://developer.salesforce.com/docs/platform/data-models/guide/academic-operations.html",connections:[{planet:"enrollment",desc:"Students enroll in programs"},{planet:"success",desc:"Program requirements drive learning plans"}]},
    {id:"course-management",name:"Course Management",icon:"\u{1F4DA}",desc:"Maintains the institutional course catalog with course descriptions, credit values, prerequisites, and corequisites. Each course record captures the subject area, course number, and level designation used in academic planning. Use Learning Wizard to create and schedule courses, and manage prerequisites, corequisites, and recommendations for enrollment in a course or program.",tags:["Course"],docs:["Modeling courses in Education Cloud relies on the Learning object, which represents information about a curriculum that can be made available as a course, program, or on-site experience. When you create a new learning record, you designate whether it is represented as a learning program or learning course. The Learning Course object then stores detailed information about a specific course within the larger learning framework.","Learning Foundation Items define prerequisites, co-requisites, or recommended learning that is required for a learning outcome. Learning Outcome Items map a learning to its related outcome, enabling institutions to track outcome-based education. Course Search in Agentforce helps students and advisors discover the right courses by answering questions about course requirements and degree planning information.","The Academic Operations app is your central location for creating and maintaining learning-related objects and the relationships between them. Staff can manage learning outcome items and learning foundation items and associate them with learning achievements. The learning, course, and program entities set up in Academic Operations become the foundation for tools in the Recruitment and Admissions and Student Success apps."],connections:[]},
    {id:"course-offerings",name:"Course Offerings",icon:"\u{1F4C5}",desc:"Schedules courses for specific academic terms with assigned instructors, meeting times, locations, and enrollment capacity. A course offering makes a learning course concrete in time and space, providing specific details including the academic session, faculty, location, start and end dates, and delivery mode. Course Operations Topics in Agentforce can create dedicated Slack channels for each course offering to centralize faculty communications.",tags:["CourseOffering"],docs:["A course offering record provides specific details including the academic session, faculty, location, start and end dates, and section number. Students register for course offerings, not courses directly. Course offering schedule records capture day-by-day schedule variations, such as different meeting times and locations for different days of the week, allowing institutions to model complex scheduling patterns.","Course Operations Topics in Agentforce help faculty maintain accurate participant lists, post course resources, share updates, and host discussions without leaving Slack. The agent can create a dedicated Slack channel for each course offering, add enrolled participants to the channel, and create a syllabus canvas. Real-time updates and easy access to course materials provide students with a unified academic experience.","The Business Rules Engine can be used to check the eligibility of students enrolling into a course, run GPA score calculations for students enrolled in an academic term, and apply complex learning requirements for learning courses and programs. Policy rules using expression sets enable institutions to enforce academic requirements at scale without custom code."],connections:[{planet:"enrollment",desc:"Students register for course offerings"},{planet:"appointments",desc:"Academic advising precedes course registration"}]},
    {id:"academic-terms",name:"Academic Terms",icon:"\u{1F4C6}",desc:"Defines the academic calendar with terms, sessions, and time periods that structure when courses are offered and when milestones occur. Education Cloud uses a hierarchy of Academic Year, Academic Term, and Academic Session objects to model any calendar complexity, from traditional semesters to nontraditional intake cycles with enrollment every six to eight weeks.",tags:["AcademicTerm","AcademicTimePeriod"],docs:["Academic Years define the entirety of the academic year. Academic Terms specify academic periods which can hold other time periods within them. Academic Sessions specify the course offering time periods based on your institution's calendar, whether that is semesters, quarters, trimesters, or other configurations. These objects are flexible enough to accommodate different schedules, overlapping terms, and nontraditional intake cycles.","Institutions can create different Academic Term records for each school within the same academic year when schools follow different schedules. Virtual programs that follow nontraditional intake cycles can use terms as short as six to eight weeks. Special immersion programs that run for extended periods can overlap with regular academic terms without conflict, as the system supports overlapping dates between term records.","Before accepting applications, creating course schedules, or enrolling students, institutions must set up their academic calendar by creating Academic Year, Academic Term, and Academic Session records. Price books for student financials are associated with academic intervals, and registration close dates on Academic Term records are used to populate close dates on opportunity records for enrollment forecasting."],connections:[{planet:"financials",desc:"Terms drive tuition fee schedules"}]},
    {id:"learning-objectives",name:"Learning Objectives",icon:"\u{1F3AF}",desc:"Captures measurable learning outcomes tied to courses and programs. Learning Outcome Items map a learning to its related outcomes, while Learning Foundation Items define prerequisites and co-requisites. Outcome Management enables institutions to define, measure, and evaluate the impact of their academic programs against desired learning outcomes.",tags:["LearningObjective"],docs:["Learning Outcome Items represent the mapping between a learning and its related outcome, enabling institutions to track whether students are achieving the intended results of their courses and programs. Learning Foundation Items define prerequisites, co-requisites, or recommended learning that is required before a student can enroll or receive credit for a given learning outcome.","Outcome Management helps educational institutions define, measure, and evaluate the impact of their outcome strategy. Institutions create various programs for advising, mentoring, and other non-scholastic activities, and Outcome Management provides the framework to assess whether those programs are achieving their intended results. This feature requires enabling and creating a custom permission set with the Manage Outcomes system permission.","The plans created in Program Plan Builder flow to Intelligent Degree Planning, which informs the Learner Progress View. This connection ensures that learning objectives defined at the program level translate into concrete progress tracking for individual students, with advisors and learners able to monitor advancement toward completion of all required outcomes."],connections:[{planet:"success",desc:"Objectives map to competency assessments"}]},
    {id:"transfer-credits",name:"Transfer Credits & Equivalencies",icon:"\u{1F504}",desc:"Evaluates and maps credits earned at other institutions to equivalent courses in the catalog. The transfer credit process uses several building blocks for the definition, submission, and evaluation of transfer credit data. A registrar creates equivalency rules that map external courses to internal courses, and all applicants from that college automatically receive the correct credit.",tags:["TransferCredit","LearningEquivalency"],docs:["An applicant creates a course credit transfer application for requests and decisions at a course, degree, or experience level. The application includes potential transfer courses, approved learning equivalencies, and verified external learning participant results from a transcript. The registrar manages the application, and a case is opened to initiate the administrative process at a college, experience, or transcript level.","External Learning records define training made available by an external provider, capturing key details to build a knowledge base of potential transfer credits for future evaluation. Learning Equivalency records define the mapping between external and internal learnings, with Learning Equivalency Achievement Mapping connecting the source achievement to the target achievement for automated credit application.","The registrar evaluates official transcripts for course, experience, or exam information, and can then automatically map results to course credit transfer application records. Once equivalency rules are established for commonly received transfer courses, the evaluation process is streamlined for future students from the same originating institutions."],connections:[{planet:"records",desc:"Transfer credits link to student education history"}]}
  ],
  dataFlow:["Academic departments define programs with degree requirements","Courses are created in the catalog with prerequisites and credit values","Course offerings are scheduled for specific terms with instructors","Equivalency rules are established for transfer credit evaluation","Academic calendar sets registration windows and deadlines"],
  connections:[{planet:"enrollment",desc:"Programs and courses define what students enroll in"},{planet:"records",desc:"Transfer credits link to student education history"},{planet:"financials",desc:"Course structure drives tuition calculation"},{planet:"success",desc:"Learning objectives tie to competency tracking"}]
},

enrollment: {
  packages: ['educationcloud'],
  name: "Enrollment",
  icon: "\u{1F4D6}",
  color: "#0ea5e9",
  description: "Tracks a student's active participation in programs and courses, from initial program enrollment through course registration, grade recording, and achievement recognition. Enrollment manages the transactional core of the student lifecycle, handling registration holds, waitlists, section changes, and withdrawal processing. Achievement records capture grades and credits that accumulate toward degree completion.",
  components: [
    {id:"program-enrollment",name:"Program Enrollment",icon:"\u{1F3C1}",desc:"Records a student's admission and active participation in a degree program or certificate. Each enrollment tracks the start term, expected graduation date, academic standing, and cumulative GPA. The Student Management app consolidates enrollment data alongside emergency contacts, relationships, and student contact information in a single accessible view for advisors and registrars.",tags:["ProgramEnrollment"],docs:["The Learner Program object tracks a student's enrollment in a learning program, including their academic standing and progress toward completion. When combined with Academic Term Enrollment records, the system maintains a term-by-term view of each student's participation. Academic Term Enrollment records must be active and contain an enrollment date for the Student Management app to display enrollment information correctly.","The Student Management app provides three tabs for viewing student data: Learner Profile showing personal details and household information, Standardized Tests listing test results, and Academic Enrollment showing an enrollment summary and enrollment details for the selected term. This consolidated view gives staff and faculty quick access to the most important student information.","Learner Pathway objects track a student's planned path to completion of their enrolled learning programs, while Learner Pathway Items represent specific requirements with completion details and status. Learner Program Requirement tracks what a student must complete in their assigned program plan, and Learner Program Requirement Progress shows their advancement toward each requirement."],connections:[{planet:"admissions",desc:"Enrollment follows admission decisions"},{planet:"records",desc:"Enrollment links to student person records"}]},
    {id:"course-registration",name:"Course Registration",icon:"\u{1F4DD}",desc:"Manages a student's registration in specific course offerings for a given term. Course offering participants track registration status, credit mode, and participant role including student, teaching assistant, or auditor. Advanced Academic Operations extends registration with AI-powered student information system capabilities that streamline and automate the process from enrollment to curriculum management.",tags:["CourseOfferingParticipant"],docs:["Course Offering Participant records link students to the courses they are taking, capturing the registration status, credit mode, and role. Course Offering Participant Result records track the outcomes of each registration, including grades and completion status. These records accumulate to build the student's academic transcript and feed into GPA calculations.","Advanced Academic Operations provides enhanced registration capabilities available in Enterprise, Unlimited, and Developer editions with the Education Cloud Advanced Academic Operations add-on license. These capabilities include streamlined registration workflows, curriculum management automation, and an Experience Cloud portal for student self-service registration.","The Business Rules Engine can be used to check the eligibility of students enrolling into a course, enforce prerequisite requirements, and apply complex academic policies. Service Process Studio enables institutions to handle registrar operations including requests for course substitutions, course waivers, term withdrawals, transcripts, or degree and graduation certificates."],connections:[{planet:"academics",desc:"Registration references course offerings"},{planet:"financials",desc:"Registration triggers fee calculation"}]},
    {id:"academic-achievement",name:"Academic Achievement",icon:"\u{1F3C6}",desc:"Records grades, credits earned, and academic milestones that mark a student's progress toward degree completion. Learning Achievement records capture the outcome of learning activities and can be configured with record types for Learning Course, Learning Program, Achievement Group, Skill, Degree, and Diploma. These records accumulate to build the student's academic transcript and feed cumulative GPA calculations.",tags:["LearningAchievement"],docs:["Learning Achievement Configuration maps learning achievement types to record types, enabling institutions to categorize outcomes by their nature. Standard configurations include Learning Course, Learning Program, and Achievement Group, with optional configurations for Skill, Degree, and Diploma. Every learning achievement type requires at least one configuration record, and the standard configuration records cannot be deleted.","Person Academic Credential records are created when a learner program record is marked as complete, capturing credentials such as degrees, certificates, or badges earned by the student. These records appear on both the Student Management Academic Enrollment tab and the Alumni community profile, providing a lifetime record of academic accomplishments that follows the student through their post-graduation engagement with the institution.","Einstein Skills Generator can be used to create Skill record types for learning achievements, enabling institutions to track competency-based outcomes alongside traditional grades. This supports outcome-based education approaches where students demonstrate mastery rather than simply accumulating seat time, with skills linked to specific courses and programs through the learning achievement framework."],connections:[{planet:"success",desc:"Achievements feed student success tracking"}]},
    {id:"enrollment-status",name:"Enrollment Status Management",icon:"\u{1F4CA}",desc:"Tracks and enforces enrollment lifecycle states including active, hold, probation, suspension, leave of absence, and withdrawal. Service Process Studio enables staff to handle registrar operations including requests for course substitutions, course waivers, term withdrawals, transcripts, and degree and graduation certificates through designed service processes.",tags:["ProgramEnrollment"],docs:["Service Process Studio lets institutions design seamless customer service processes that staff can launch to handle common registrar operations. Use cases include handling requests for course substitutions, course waivers, term withdrawals, transcripts, and degree and graduation certificates. Student operations include changing contact information, changing learning programs, and new or changed declarations of majors and minors.","Record Alerts monitor enrollment status changes and notify advisors when intervention is needed. Academic holds can trigger advising requirements before a student can register for the next term, while financial holds block registration until outstanding balances are resolved. The Business Rules Engine can automate enrollment eligibility checks, ensuring students meet all requirements before proceeding.","Stage Management provides additional control over enrollment lifecycle transitions. Fulfillment Plans, Fulfillment Steps, Fulfillment Step Dependencies, and Stage Transition Entries enable institutions to model complex enrollment workflows where multiple conditions must be met in a specific sequence before a status change is allowed."],connections:[{planet:"financials",desc:"Financial holds affect enrollment status"}]},
    {id:"learning-plans",name:"Learning Plans",icon:"\u{1F5FA}",desc:"Creates personalized academic roadmaps that sequence courses across terms toward degree completion. Intelligent Degree Planning gives learners a dynamic degree planning experience in the Student Success app. Learning Pathway Templates provide reusable plans that students can apply to create their own planned learning paths.",tags:["LearningPlan"],docs:["Learning Pathway Templates provide a reusable template that a learner can apply to create a planned learning path. Each template contains Learning Pathway Template Items representing requirements with completion details, and Learning Pathway Template Program Plans that connect specific program plans to the template. This allows institutions to create standard degree pathways that students can adopt and customize.","Intelligent Degree Planning in the Student Success app enables advisors and students to visualize degree progress and plan future course selections. The plans created in Program Plan Builder flow to Intelligent Degree Planning, which informs the Learner Progress View. The Intelligent Program Comparison Engine gives learners a side-by-side comparison of their enrolled program with up to three other programs they are considering.","Learner Progress components can be included on the Experience Cloud site so that learners track their academic advancement. Advisors see Learner Progress as a tab on a learner's case record page in Student Success. Learner Progress Summary provides a quick view of academic highlights, while the full Learner Progress view shows detailed requirement-by-requirement advancement toward degree completion."],connections:[{planet:"success",desc:"Learning plans support student success tracking"},{planet:"appointments",desc:"Plan adjustments often require advising appointments"}]}
  ],
  dataFlow:["Admitted student is enrolled in a degree program","Student registers for course offerings each term","System enforces prerequisites, capacity limits, and time conflicts","Grades are recorded and achievements accumulate","Learning plans track progress toward degree completion"],
  connections:[{planet:"admissions",desc:"Enrollment follows admission decisions"},{planet:"academics",desc:"Enrollment references courses, programs, and terms"},{planet:"records",desc:"Enrollment records link to person accounts"},{planet:"success",desc:"Enrollment progress feeds student success tracking"},{planet:"financials",desc:"Course registration triggers fee calculation"},{planet:"appointments",desc:"Registration may require advising appointments"}]
},

records: {
  packages: ['educationcloud'],
  name: "Student Records",
  icon: "\u{1F464}",
  color: "#10b981",
  description: "The central person data domain that anchors every other part of Education Cloud. Student Records maintains the unified learner profile built on Salesforce Person Accounts, capturing demographics, contact points, family relationships, education history, examination scores, language proficiency, and employment records. Every domain reads from and writes to student records, making it the gravitational center of the data model.",
  components: [
    {id:"person-accounts",name:"Person Accounts",icon:"\u{1F464}",desc:"The core student record built on the Salesforce Person Account model, combining Account and Contact functionality into a single entity. Faculty, staff, administrators, students, and alumni are all modeled with Person Accounts. The Contact Profile object tracks biographic and demographic information such as birth date, ethnicity, first-generation student status, and citizenship, creating a unified student record.",tags:["Account"],docs:["Faculty, staff, administrators, students, and alumni are modeled with the Person Account object, which is a standard Salesforce object. The Contact Profile object is associated with the Contact object and allows tracking of biographic and demographic information. When this data is woven together, the result is a unified student record that helps institutions see, understand, and serve the whole person behind the data.","The Constituent Role object records information related to a person's role at the institution, enabling institutions to segment person accounts by role for reporting, record sharing, and communication purposes. Educational institutions serve individuals in a variety of roles including suspects, prospects, applicants, students, faculty, staff, alumni, donors, and parents, and understanding these relationships is key to serving them properly.","When an applicant registers on the learner portal, Education Cloud automatically creates a person account for them. To prevent duplicate records when converting person accounts to Experience Cloud users, institutions should include an email address on the existing person account. The Student Management app provides a consolidated view of student records with tabs for Learner Profile, Standardized Tests, and Academic Enrollment."],connections:[{planet:"enrollment",desc:"Person accounts are the identity anchor for enrollments"},{planet:"admissions",desc:"Applicants are linked to person accounts"}]},
    {id:"contact-points",name:"Contact Points",icon:"\u{1F4DE}",desc:"Manages multiple addresses, phone numbers, and email addresses for each student with usage designations like home, school, billing, and emergency. The Student Management app adds Contact Point Addresses, Contact Point Phones, and Contact Point Emails to the Person Account page layout, providing a consolidated view of all contact information for advisors, registrars, and faculty.",tags:["ContactPointAddress","ContactPointPhone","ContactPointEmail"],docs:["Contact Point Address, Contact Point Phone, and Contact Point Email objects are added to the Person Account page layout through the Student Management app setup. Each student can have multiple addresses, phone numbers, and email addresses with different usage types such as home, school, billing, and permanent. Primary designation determines which contact point is used for official communications.","Address management is important for keeping address data accurate and organized. For constituents, institutions use the contact fields such as mailing address, and for business contacts, the account fields such as billing address. Constituents often have multiple addresses used at various times of the year, and historical address tracking ensures outreach materials and acknowledgments reach the correct address.","The Student Management app's Learner Profile tab shows personal details, emergency contacts, additional contact information, citizenship information, demographic information, and household relationship information in a single consolidated view. This gives staff and faculty quick access to the most important student contact data without navigating between multiple records."],connections:[]},
    {id:"relationships",name:"Relationships & Household",icon:"\u{1F46A}",desc:"Maps family, guardian, and household relationships between person records using Group Membership objects, Account Contact Relationships, and Contact Contact Relationships. Actionable Relationship Center visualizes these connections in an interactive graph, helping staff understand household structures, sibling relationships, and guardian networks at a glance.",tags:["ContactRelationship"],docs:["Education Cloud uses a variety of objects to represent people, families, organizations, and relationships. Person accounts represent nearly all individuals, while household accounts represent families and business accounts represent organizations, schools, colleges, departments, and services. Group Membership objects link individuals to households, other individuals, services, or organizations.","Actionable Relationship Center provides interactive relationship graphs that can be added to student records to show household information. Staff can view a student's household members including parents, guardians, and siblings, and see the relationships between household members. The Education Cloud Person Account Relations template provides a starting point for configuring these visualizations.","When an applicant enters a family member such as a guardian or sibling on their application, a Contact Relationship record is created capturing the relationship between the student and their family member. These relationships support sharing sets for parents, guardians, and agents who submit applications on behalf of students, enabling appropriate access controls for family members interacting with the institution."],connections:[{planet:"mentoring",desc:"Mentoring profiles reference person relationships"}]},
    {id:"education-history",name:"Education History",icon:"\u{1F4DC}",desc:"Stores prior education records from high school and previous institutions including school name, dates attended, degree earned, GPA, and class rank. When an applicant enters their high school education history or a guardian's education level on the application, a Person Education record is created. These records support transfer credit evaluation and admissions decisions.",tags:["PersonEducation"],docs:["Person Education records capture information about professional education for a person, including the institution name, dates attended, degree earned, GPA, and class rank. These records are created automatically when applicants enter their educational background through the application form, and they appear on both the student's records and the alumni profile page.","High school records capture standardized information needed for undergraduate admissions evaluation, while previous institution records provide context for transfer credit assessment. The education history is displayed on the Student Management app's person account page and is shared with external reviewers through permission sets that grant Read access to Person Education objects.","Person Academic Credential records complement education history by capturing credentials earned at the institution, such as degrees, certificates, or badges. These records are automatically created when a learner program record is marked as complete, providing a comprehensive view of both external and internal educational achievements for each student."],connections:[{planet:"academics",desc:"Education history informs transfer credit evaluation"}]},
    {id:"examinations",name:"Examinations & Test Scores",icon:"\u{1F4DD}",desc:"Records standardized test scores including SAT, ACT, GRE, TOEFL, IELTS, and AP exams. When an applicant enters scores from a standardized test on their application, a Person Examination record is created capturing the composite or single-section score. The Student Management app displays standardized test results on a dedicated tab.",tags:["PersonExamination"],docs:["Person Examination records store test names, dates taken, individual section scores, and composite or total scores. These records are created automatically when applicants enter their test information through the application form and are used during admissions evaluation, placement decisions, and credit-by-examination processing.","The Student Management app includes a Standardized Tests tab that lists the results of all standardized tests a student has taken. Permission sets for internal users, applicants, and external reviewers include Read, Create, Edit, and Delete access to Person Examination records, enabling staff to manage test score data throughout the admissions and enrollment process."],connections:[{planet:"admissions",desc:"Test scores inform admission decisions"}]},
    {id:"demographics-languages",name:"Demographics & Languages",icon:"\u{1F30D}",desc:"Captures language proficiency levels, employment history, and additional demographic information used for institutional reporting, compliance, and personalized student services. When applicants enter a language in the Language Proficiency section of the application form, a Person Language record is created. Employment records capture both current and historical positions for career outcome reporting.",tags:["PersonLanguage","PersonEmployment"],docs:["Person Language records store language proficiency information that supports international student services, ESL placement, and institutional compliance reporting. Person Employment records track work-study positions, internships, and post-graduation jobs, with employer name, job title, dates, and employment type. Post-graduation employment data feeds institutional career outcome reporting.","Person Employment records must be connected to the alumni user's contact record to show on their profile page in the alumni portal. The Alumni Relations app displays employment history from the Person Employment related list, and staff can create employment records directly from the alumni account record page. This data supports career outcome tracking and alumni engagement strategies."],connections:[{planet:"alumni",desc:"Employment data tracks post-graduation outcomes"}]}
  ],
  dataFlow:["Person account is created during recruitment or application","Contact points, relationships, and demographics are populated","Education history and test scores are added for admissions evaluation","Record is enriched throughout the student lifecycle","Post-graduation data tracks alumni employment and engagement"],
  connections:[{planet:"recruitment",desc:"Prospect data creates person records"},{planet:"admissions",desc:"Applicant data stored on person records"},{planet:"academics",desc:"Education history informs transfer credit evaluation"},{planet:"enrollment",desc:"Student identity for all enrollment records"},{planet:"success",desc:"Competencies and traits linked to person"},{planet:"financials",desc:"Financial accounts linked to person records"},{planet:"mentoring",desc:"Mentor/mentee profiles reference person records"},{planet:"alumni",desc:"Alumni status tracked on person records"},{planet:"appointments",desc:"Appointments reference student records"},{planet:"data360",desc:"Identity resolution unifies duplicate person records"}]
},

success: {
  packages: ['educationcloud'],
  name: "Student Success",
  icon: "\u{1F31F}",
  color: "#22c55e",
  description: "Empowers advisors and students to track competencies, personal traits, career interests, and academic progress toward degree completion. Student Success brings together competency assessment, early alert systems, and career development planning into a holistic framework for student support. AI-powered advising agents surface at-risk students and recommend interventions based on engagement patterns and academic performance.",
  components: [
    {id:"competency-tracking",name:"Competency Tracking",icon:"\u{1F4AA}",desc:"Records and assesses student skills and proficiencies against defined competency frameworks. Person Competency records capture the skill area, proficiency level, assessment method, and evidence of achievement. These records are used by the Student Goals Agent to provide personalized goal recommendations based on the student's skills and proficiency levels.",tags:["PersonCompetency"],docs:["Person Competency records document a student's skills and proficiencies, such as Python programming or public speaking, with assessed proficiency levels. These records are accessed by the Student Goals Agent's grounding flow to provide context-aware recommendations. Competencies can be mapped to learning objectives, enabling outcome-based education tracking where students demonstrate mastery.","Competency data feeds into the Intelligent Degree Planning experience, helping advisors understand where students have demonstrated required skills and where gaps remain. Combined with Person Traits and Person Affinities, competency records provide a holistic view of each student's strengths and development areas that inform personalized advising conversations.","Intake assessments administered through the Discovery Framework during program enrollment capture competency information systematically. Responses are saved as records related to the program enrollment, and advisors can review them to understand the learner's requirements and determine the best support approach."],connections:[{planet:"academics",desc:"Learning objectives map to competency assessments"}]},
    {id:"traits-affinities",name:"Traits & Affinities",icon:"\u{1F9E0}",desc:"Captures student strengths, personality characteristics, and interest areas that inform personalized advising and career guidance. Person Traits describe characteristics such as leadership or analytical thinking, while Person Affinities map preferences and interests such as sustainability or mobile app development. These records are used by the Student Goals Agent to ground personalized goal recommendations.",tags:["PersonTrait","PersonAffinity"],docs:["Person Traits capture unique student characteristics or attributes, such as Leader or Detail-Oriented, identified through assessments or advisor observations. Person Affinities map the student's preferences and interests, such as specific academic subjects, career aspirations, or extracurricular activities. Both are used by the Student Goals Agent's grounding flow to provide context-aware recommendations.","The Student Goals Agent leverages specific student attributes including traits, competencies, affinities, involvement group memberships, first-generation status, academic profile, and assessment results to provide personalized recommendations. Before deployment, institutions must ensure transparency about what data is being used, why, and how it informs the agent's suggestions.","Involvement groups empower students to explore new interests and hone their talents, complementing the trait and affinity data with information about campus engagement. Advisors can access these records alongside career and interest assessments to recommend the right fit for each student based on their complete profile."],connections:[]},
    {id:"advising",name:"Academic Advising",icon:"\u{1F91D}",desc:"Coordinates advisor-to-student assignments and tracks advising interactions, notes, and action items. The Student Success app provides a central place to track and drive learner success at the individual level, with features for creating care plans, managing alerts, assigning success teams, and enrolling students in programs and benefits. Einstein Advising Summary uses generative AI to quickly prepare advisors for appointments.",tags:["CareCoordinator","CareRole"],docs:["The Student Success app enables advisors to create and manage personalized care plans that help learners achieve educational success. Care plans include benefits, goals, and tasks assigned to students. Action plans provide task-managed checklists for to-do lists during enrollment, care plans for students, and application or matriculation processes. The Action Center component on the Experience site helps learners keep track of their care plans, action plans, and tasks.","Success Teams enable institutions to create and assign case teams that support each learner's journey. Multiple coordinators can be assigned to a single student for different support areas. Interaction summaries provide structured, searchable notes with smart search and filters, enabling advisors to share meeting notes, add tags for discussed topics, and create appropriate action items all in one place.","Student Advising Topics in Agentforce assist and optimize your advising team's efforts. Advisors can use the agent to summarize advising cases, get answers to questions about campus resources and policies, and follow up proactively by suggesting next-best actions such as creating to-dos or cases. The Learner Watchlist helps advisors proactively monitor learners who require enhanced support and ensure timely intervention."],docUrl:"https://developer.salesforce.com/docs/platform/data-models/guide/student-success.html",connections:[{planet:"appointments",desc:"Advising sessions scheduled as appointments"},{planet:"agentforce",desc:"AI advising agent surfaces at-risk students"}]},
    {id:"academic-alerts",name:"Academic Alerts",icon:"\u{26A0}",desc:"Triggers early warning notifications when students show signs of academic difficulty, disengagement, or risk of dropout. Record Alerts in Education Cloud monitor learner performance with respect to attendance, grades, and other metrics. Flows can automate alert creation at scale, with customizable alert cards built using OmniStudio and the ability to track the origin of alerts from external systems.",tags:["Case"],docs:["Record Alerts enable advisors and staff to be notified about changes in records that require action, so staff can take proactive steps and leverage care plans for a learner. Alert schedules can be customized, and alerts can be automated using flows for mass application. OmniStudio allows customization of record alert cards to display the most relevant information for each alert type.","In K-12 schools, teachers, counselors, and support staff are alerted to students who need support based on the ABCs: attendance, behavior, and courses. In higher education, alerts can be created for academics, careers, financial aid, and housing. Each alert is routed to the appropriate advisor with the context needed to determine the best intervention.","Pulse Checks provide a complementary feedback mechanism, allowing institutions to get learner feedback and assess engagement, satisfaction, and overall wellbeing. Student Insights powered by Data Cloud and Einstein generative AI enable advisors to get relevant, holistic insights on students by importing data from external systems, providing a more complete picture of each student's situation."],connections:[{planet:"enrollment",desc:"Enrollment data triggers academic alerts"}]},
    {id:"career-development",name:"Career Development",icon:"\u{1F680}",desc:"Helps students explore career paths, set professional goals, and build career readiness through structured development activities. Career Planning and Life Goals offers personalized guidance and comprehensive tools to help students define and achieve goals based on their profile, preferences, and assessment insights. The Student Goals Agent provides AI-powered SMART goal recommendations.",tags:["PersonCompetency","PersonAffinity"],docs:["Career Planning and Life Goals enables students to access a library of career and interest assessments, explore campus involvement groups, track memberships and associated roles, and manage their profile and preferences more efficiently. Students can set, update, and track specific, measurable, achievable, relevant, and time-bound career and life goals through the learner portal.","The Student Goals Agent uses AI to help students get personalized goal recommendations based on their academic data, engagement data, and self-reported assessment information. The agent considers major, GPA, academic standing, year of study, first-generation status, campus group memberships, and career or interest assessment results to provide context-aware guidance. Students can also get campus resource recommendations including courses, support programs, and involvement groups.","Advisors can access involvement groups and a library of career and interest assessments, and recommend the right fit to students based on the student's profile, preferences, and assessment insights. The agent's recommendations serve as a starting point for exploration rather than prescriptive plans, and institutions are encouraged to establish clear usage boundaries and escalation protocols for sensitive interactions."],connections:[{planet:"alumni",desc:"Alumni career data informs current student planning"}]}
  ],
  dataFlow:["Student's competencies, traits, and affinities are assessed and recorded","Advisor is assigned based on program, year, and caseload","Early alert system monitors academic performance and engagement","Alerts trigger interventions and advising sessions","Career development planning guides students toward post-graduation goals"],
  connections:[{planet:"academics",desc:"Learning objectives tie to competency tracking"},{planet:"enrollment",desc:"Course performance feeds success interventions"},{planet:"records",desc:"Success metrics stored on person records"},{planet:"mentoring",desc:"Mentoring outcomes feed into success tracking"},{planet:"appointments",desc:"Advising appointments support interventions"},{planet:"agentforce",desc:"AI advising agent surfaces at-risk students"}]
},

financials: {
  packages: ['educationcloud'],
  name: "Student Financials",
  icon: "\u{1F4B0}",
  color: "#f59e0b",
  description: "Manages tuition, fees, financial aid, and student account balances through the Salesforce pricing and order engine adapted for higher education. Student Financials uses Products and Price Books to model fee structures, Academic Orders to generate student charges, and pricing rules to handle complex scenarios like in-state versus out-of-state tuition, lab fees, and meal plan charges.",
  components: [
    {id:"fee-management",name:"Fee Management",icon:"\u{1F4B5}",desc:"Defines the institution's fee structure using Salesforce Products. Use products to model student fees such as in-state tuition, international student tuition, lab fees, and meal plans. After creating products, you link them together in price books that you associate with academic intervals such as the current fall term, with support for multiple price books that change yearly or vary by learner attributes.",tags:["Product2"],docs:["Student Financials bridges the gap between students and their financial accounts by setting up a fee management framework in Education Cloud. The framework uses the Salesforce pricing and order engine adapted for higher education, loading tuition and fees for each academic interval and applying fees to learning programs and courses.","Products represent individual fee types in the institution's financial structure. After creating products, they are linked together in price books associated with academic intervals. You can create multiple price books for fees that change yearly or vary based on learner attributes such as residency status, program level, or enrollment intensity. Price Book Academic Interval records specify that a pricebook applies for a given academic session, term, or year.","Accounting Subledger can be used to process and prepare the financial data captured by various departments for the Accounting department, providing fund allocation and integration with an external accounting system. Use cases include grants, scholarships, donations, tuition, library fees, food programs, and application fees."],connections:[{planet:"academics",desc:"Course and program structure determines applicable fees"}]},
    {id:"price-books",name:"Price Books & Schedules",icon:"\u{1F4D5}",desc:"Establishes term-specific pricing through Salesforce Price Books. Price Book Academic Interval records specify that a pricebook applies for a given academic session, term, or year, and you can associate multiple price books with each academic interval. Price book entries link products to their monetary values, supporting multiple pricing tiers for different student populations.",tags:["Pricebook2","PricebookEntry"],docs:["Price books are associated with academic intervals through the Price Book Academic Interval object. Each interval, whether it is a session, term, or year, can have multiple price books to support different fee structures for different student populations such as in-state versus out-of-state, undergraduate versus graduate, or full-time versus part-time students.","A Decision Table template for Price Book Academic Interval Entries provides automated lookup of the correct price book entries for a given academic interval, streamlining the fee calculation process. This decision table works alongside the Pricing Procedure Template Expression Set and the order context definition to create a complete pricing pipeline for student charges."],connections:[]},
    {id:"academic-orders",name:"Academic Orders",icon:"\u{1F6D2}",desc:"Generates student financial charges by creating orders populated with fee products. The Create Learner Order invocable action creates an order for a given learner and an associated academic order for a given learner and academic term. You can incorporate the action into workflows using flows, business APIs, and OmniStudio Flexcards, with batch management support for bulk calculations.",tags:["AcademicOrder","OrderProduct"],docs:["Academic orders are generated using the Salesforce-provided Create Learner Order invocable action, which creates both an order for the learner and an associated academic order for the relevant academic term. The action can be incorporated into organizational workflows using flows, business APIs, and OmniStudio Flexcards. For bulk calculations across many students, institutions should use flows with batch management.","Pricing resources include a Pricing Procedure Template Expression Set for student fee calculations, an order context definition for events related to orders and order items, and a Price Book Academic Interval decision table for price book entries in an academic interval. Institutions can customize the expression set template to apply discounts and special pricing rules.","The Student Financials Agent helps students retrieve their account balances and understand the fees included. The agent includes a Student Fee Management topic that provides detailed fee breakdowns and explanations for specific academic terms, answering questions about fee amounts, descriptions, and optional fee types. The Student Account Management topic provides total fee balances given specific attendance dates."],connections:[{planet:"enrollment",desc:"Course registration triggers order generation"}]},
    {id:"payment-processing",name:"Payment Processing",icon:"\u{1F4B3}",desc:"Tracks payments received, payment plans, and outstanding balances on student accounts. The Student Financials Agent helps students view their account balances, get a detailed breakdown of their fees, and obtain more information about a given fee. Balance calculations aggregate charges and payments to show real-time account standing.",tags:["AcademicOrder"],docs:["Student financial account management is enabled through the Education Cloud setup, which configures order creation settings and pricing settings including price book options. Sharing settings for financial objects including Academic Term, Academic Term Enrollment, Order, Order Product, Academic Order, Contact Profile, and Account must be set to Public Read Only for the system to function properly.","The Student Financials Agent's Student Account Management topic provides total fee balances given specific attendance dates, along with fee breakdowns and account history details. Students can ask questions about their balances and receive detailed explanations of how charges were calculated, reducing the need for staff-assisted billing inquiries."],connections:[{planet:"enrollment",desc:"Financial holds can block registration"}]},
    {id:"financial-aid",name:"Financial Aid",icon:"\u{1F381}",desc:"Manages scholarship, grant, and aid award packaging for eligible students. The Pricing Procedure Template Expression Set can be customized to apply discounts and aid adjustments during academic order pricing. The Business Rules Engine can check the eligibility of students who have an immediate need for financial aid, applying complex rules without custom code.",tags:["AcademicOrder","OrderProduct"],docs:["Financial aid awards interact with the pricing engine to calculate net cost to the student after aid is applied. The expression set template for student fee calculations can be customized to apply institutional scholarships, grants, and other discount types as part of the order generation process. This ensures that financial aid is reflected accurately on student account statements.","Accounting Subledger processes and prepares financial data captured by various departments for the Accounting department, providing fund allocation and integration with external accounting systems. Use cases specific to financial aid include grants, scholarships, and donations, with full tracking of how funds are allocated and disbursed across the institution."],connections:[{planet:"admissions",desc:"Financial aid packaging tied to admission offers"}]}
  ],
  dataFlow:["Institution defines fee products with pricing attributes","Price books establish term-specific fee amounts","Student registers for courses, triggering order generation","Pricing rules evaluate student attributes to calculate charges","Financial aid is applied and payment plans are created","Student account balance is updated with net amount due"],
  connections:[{planet:"admissions",desc:"Application fees and financial aid packaging"},{planet:"enrollment",desc:"Registration triggers tuition charges"},{planet:"academics",desc:"Program and course structure drives fee schedules"},{planet:"records",desc:"Financial accounts linked to person records"},{planet:"alumni",desc:"Scholarship funds connect to advancement"},{planet:"agentforce",desc:"Financial aid agent answers billing questions"},{planet:"experience",desc:"Student financial self-service portal"},{planet:"analytics",desc:"Financial health dashboards"}]
},

mentoring: {
  packages: ['educationcloud'],
  name: "Mentoring",
  icon: "\u{1F91D}",
  color: "#f472b6",
  description: "Manages structured mentoring programs that pair students with mentors for academic guidance, career coaching, and personal development. Mentoring uses profile-based matching enhanced by AI to find optimal mentor-mentee pairings based on skills, interests, academic background, and career goals. Benefit assignment workflows track the specific support each mentee receives throughout the mentoring relationship.",
  components: [
    {id:"program-design",name:"Program Design",icon:"\u{1F4CB}",desc:"Defines mentoring programs with goals, eligibility criteria, duration, and available benefits. With the Mentoring app, facilitators create and manage programs and set the benefits they contain. Mentees enroll in programs through the mentee portal, mentors register as benefit providers in the mentor portal, and facilitators use assessments to connect mentees with mentors who can address their needs.",tags:["MentoringProgram"],docs:["A mentoring program plays a pivotal role in enhancing the overall experience and personal development of members of your institution. Programs benefit participants through academic guidance, career development, personal growth and support, networking opportunities, retention and engagement, skill development, and diversity and inclusion. The mentorship experience can have a profound and lasting effect on participants.","Education Cloud's Mentoring app enables facilitators to create programs, create mentoring profiles, assign mentors to mentees, manage assessments, and track benefit disbursements. Programs can be set up as support programs with the option to assign Advising or Mentoring benefit types, add benefits, assign success teams, and add intake assessments through a guided flow.","Benefit types available with Education Cloud include Advising for counseling and assistance, Goods for items such as stationery or equipment, Mentoring for guidance, Monetary for scholarships or donations, and Session for workshops with multiple scheduled sessions. Each benefit specifies enrollment count, unit of measure, minimum and maximum benefit amounts, and a goal definition that outlines the hierarchy of goals for the mentoring benefit."],connections:[]},
    {id:"mentor-profiles",name:"Mentor & Mentee Profiles",icon:"\u{1F464}",desc:"Captures detailed profiles for both mentors and mentees including skills, experience areas, availability, communication preferences, and goals. Profile fields for comparison can include subject area or industry, in-person or virtual meeting preference, location, and days and times available. A record-triggered flow can automatically create profiles when participants complete an assessment.",tags:["MentoringProfile"],docs:["Mentoring profiles identify the role, preferences, and interests of participants. Profile fields are configurable per program, and possible comparison fields include subject area, industry, channel preference (virtual or in-person), days available, times available, skills, and location. Lookup relationships, master-detail relationships, and system fields are not supported for comparison.","Use Experience Builder to create a portal where mentors and mentees can discover and enroll in mentoring benefits. In the portal, users can respond to assessments that help match a mentor with a mentee, see benefit assignments, and see details of their mentoring interactions. Separate audiences should be created for mentor and mentee profiles to ensure each user type sees the appropriate content and functionality.","There are several varieties of mentors: senior students or staff who provide tutoring, alumni who help with networking or skills development, and outside organizations that set up work-study programs. Mentors are represented using the Provider Offering object. A user becomes a mentee when they enroll in a mentoring program or when a related program enrollment record is identified in their profile."],connections:[{planet:"records",desc:"Profiles reference person account records"}]},
    {id:"mentor-matching",name:"AI-Powered Matching",icon:"\u{1F916}",desc:"Uses Einstein comparison algorithms to analyze mentor and mentee profiles and recommend optimal pairings. The Mentor Comparison screen flow compares potential mentors with a mentee based on profile fields such as subject area, meeting preference, location, and availability. Program administrators review suggested matches and can accept, reject, or manually override recommendations before finalizing pairings.",tags:["MentoringProfile"],docs:["Mentoring profile records help connect mentees with suitable mentors. Profile fields for comparison can include subject area or industry, in-person or virtual meeting preference, location, and days and times the participant is available. You can add any custom fields that help match the ideal mentor with each mentee, although lookup relationships, master-detail relationships, and system fields are not supported for comparison.","Discovery Framework enables institutions to create assessments with predefined questions that are added to mentoring programs. When learners enroll in a mentoring program through the portal, the assessment questionnaire appears automatically. Submitted responses are saved as records related to the program enrollment, and facilitators can review the responses to clearly understand the learner's requirements and determine how best to support them.","A record-triggered flow can be built to automatically create Mentoring Profile records when mentors and mentees complete an assessment. This automation saves time and ensures that matching-relevant information is captured consistently. The matching process considers all configured profile fields and their assigned weights to generate the best possible pairings for each program."],connections:[]},
    {id:"benefit-assignment",name:"Benefit Assignment & Tracking",icon:"\u{1F4E6}",desc:"Assigns and tracks the specific benefits a mentee receives from their mentoring relationship. When a mentee enrolls in a mentoring program, a benefit assignment record is created. From this record page, facilitators can see highlights, enrollee and provider information, a timeline of mentoring activities, and related lists for alerts, action plans, interaction summaries, and assessments.",tags:["MentoringBenefit","MentoringBenefitAssignment"],docs:["The benefit assignment record page serves as the central management point for each mentoring relationship. Facilitators can see names and contact information for the enrollee (mentee) and benefit provider (mentor), take action such as creating alerts, adding notes, creating tasks, and sending email, and view a timeline of mentoring activities. Benefit assignment records should be created using the Benefit Assignments tab rather than the related list on the account record.","Benefit providers can be alumni who help students network with professionals, organizations that set up work-study programs, or senior students who provide tutoring to first-year students. Users can register as benefit providers on an Experience Cloud site when institutions enable the Register as Provider option on the benefit record. This creates a provider offering record linking the mentor to the specific benefit they can provide.","The Mentoring app home page gives facilitators a single view of benefit assignments that do not have a mentor assigned, records for users who serve as mentors, daily and upcoming tasks, and assessment management. The Unmatched Benefit Assignment list view shows all benefit assignments where a provider offering is not yet specified, helping facilitators identify mentees who still need to be matched with a mentor."],connections:[{planet:"success",desc:"Mentoring outcomes feed student success metrics"}]}
  ],
  dataFlow:["Program administrator defines mentoring program and benefits","Mentors and mentees create profiles with matching-relevant information","AI matching engine compares profiles and suggests optimal pairings","Administrator reviews and finalizes mentor-mentee assignments","Benefits are assigned and progress is tracked throughout the relationship"],
  connections:[{planet:"records",desc:"Mentor/mentee profiles linked to person records"},{planet:"success",desc:"Mentoring outcomes tracked as success metrics"},{planet:"appointments",desc:"Mentoring sessions scheduled as appointments"}]
},

alumni: {
  packages: ['educationcloud'],
  name: "Alumni & Advancement",
  icon: "\u{1F3C5}",
  color: "#ec4899",
  description: "Engages alumni through lifetime relationship management, gift tracking, pledge fulfillment, and volunteer coordination. Alumni & Advancement connects giving data to institutional advancement goals, provides donor stewardship tools, and tracks the impact of fundraising campaigns. The alumni engagement lifecycle extends the student record with post-graduation career outcomes, event participation, and philanthropic activity.",
  components: [
    {id:"alumni-engagement",name:"Alumni Engagement",icon:"\u{1F465}",desc:"Tracks ongoing relationships with graduates through event participation, communication interactions, volunteer activities, and career updates. Alumni Engagement Metrics combines Data 360 and Einstein generative AI to not only track alumni activities but provide informative translations of that data to give a true sense of each alumnus's engagement level across communications, experiential, volunteering, and philanthropic categories.",tags:["Account"],docs:["Education Cloud provides a 360-degree view of learners throughout their educational journey from prospect to proud, involved alumni. The Alumni Relations app enables staff to manage alumni information and help alumni stay engaged and invested in their alma mater. Alumni relations coordinators and managers get a single home page view of alumni activity with the ability to create action-based alerts and activities.","Alumni Engagement Metrics uses Data 360 calculated insights to classify engagement across four categories: Communications, Experiential, Volunteerism, and Philanthropic. Each category is scored as High, Medium, Low, or Not Applicable based on activity counts. The Engagement Visualization Panel component shows these insights on person account record pages, with Einstein generative AI providing narrative summaries of each alumnus's involvement.","The Alumni Relations Console gives coordinators a central place to focus on engagement. The dashboard visualizes engagement based on key performance indicators, with the ability to filter by college or department, see alumni with open alerts and cases, view the number of alumni who have created portal accounts, and see learning achievements earned from other institutions."],connections:[{planet:"records",desc:"Alumni are former students with person records"},{planet:"experience",desc:"Alumni portal for community engagement"}]},
    {id:"gift-management",name:"Gift Management",icon:"\u{1F381}",desc:"Records and processes charitable gifts including cash, securities, in-kind donations, and matching gifts. Fundraising in Education Cloud provides tools for engaging donors, raising funds, and driving outcomes with specialized tools and data-driven insights. Gift entry supports individual gifts or gift batches using templates that enable quick creation of entries with the same set of fields.",tags:["GiftTransaction"],docs:["When Fundraising is enabled in Education Cloud, institutions have access to all the features, objects, fields, invocable actions, and APIs needed to manage gifts. This includes gift transactions for tracking individual donations, gift designations for allocating funds to specific purposes, gift soft credits for recognition, and gift tributes for memorial or honorary gifts.","Gift entry and processing supports entering gifts individually or adding them to a gift batch. A gift batch uses a template that enables quick creation of entries sharing the same set of fields. Institutions can track donations received as one-time gifts or installments fulfilling a commitment. Gift acknowledgment and tax receipt features allow quick and easy provision of acknowledgments to donors.","Advancement in higher education makes sure institutions meet the evolving needs of students, teachers, and society. Activities such as fundraising, alumni relations, public relations, strategic planning, and community engagement all contribute to advancing the institution's mission. Education Cloud includes Alumni Relations for engagement management, Alumni Engagement Metrics for data-driven insights, and Fundraising for gift operations."],connections:[{planet:"financials",desc:"Gift funds connect to institutional finance"}]},
    {id:"gift-commitments",name:"Pledges & Commitments",icon:"\u{1F4DD}",desc:"Manages multi-year pledges and recurring giving commitments where donors commit to future gifts over a defined period. Fundraising in Education Cloud lets institutions manage all types of gift commitments, both monetary and in kind, track gifts for particular opportunities and campaigns, change transaction schedules, and update donation amounts.",tags:["GiftCommitment"],docs:["Gift commitments track the total pledged amount, payment schedule, amount received to date, and outstanding balance. Automated tasks simplify handling recurring donations, and institutions can easily monitor upcoming, missed, failed, and recently paid and refunded transactions. Commitment records link to individual gift transactions that fulfill the pledge over time.","Gift Planning enables institutions to establish multiyear philanthropic journeys for prospects and donors that include complex planned gifts such as charitable gift annuities, trusts, life insurance, donor-advised funds, and bequests. This capability helps streamline and automate processes, reduce inefficiencies, and ensure compliance with evolving legal and institutional policies."],connections:[]},
    {id:"volunteering",name:"Volunteer Management",icon:"\u{270B}",desc:"Coordinates alumni volunteer activities including mentoring current students, serving on advisory boards, participating in career panels, and supporting campus events. Volunteer Management in Education Cloud streamlines program management, enhances the volunteer experience, tracks hours, and reports metrics through an Experience Cloud portal.",tags:["VolunteerActivity"],docs:["Volunteer Management enables institutions to manage volunteer programs such as alumni mentoring, parent associations, and campus events. In Experience Cloud, institutions create a portal to post opportunities and let volunteers browse, search, and sign up. The system collects and evaluates volunteer applications, schedules volunteers, tracks hours, and reports on volunteer impact.","Alumni Engagement Metrics tracks volunteerism activities as one of four engagement categories, along with communications, experiential, and philanthropic activities. The Meaningful Impact Summarization flow creates summaries describing alumni involvement in volunteer roles that are endorsed and highly valued by the institution, providing narrative context for engagement data."],connections:[{planet:"mentoring",desc:"Alumni volunteers serve as mentors"}]},
    {id:"fundraising",name:"Fundraising Campaigns",icon:"\u{1F4C8}",desc:"Plans and executes fundraising campaigns with goals, timelines, prospect assignments, and progress tracking. Scoring frameworks like the Recency, Frequency, and Monetary value score help identify the best donor fits for each campaign. Outreach source codes identify which outreach methods drive the most successful results, enabling data-driven campaign optimization.",tags:["Campaign"],docs:["Scoring frameworks help increase fundraising success by identifying donors who are the best fit for each campaign or outreach program. Matching donors to specific outreach endeavors improves fundraising outcomes and strengthens constituent relationships. The Recency, Frequency, and Monetary value (RFM) score is a standard framework available for donor analysis.","Outreach source codes identify the outreach methods used with campaigns to help determine which approaches are successful. Philanthropic research capabilities enable institutions to identify, track, and act on data about persons or organizations that helps build fundraising relationships. Donor profiles consolidate key donor information in one place for advancement officers.","Fundraising provides tools for engaging donors, raising funds, and driving outcomes with specialized tools and data-driven insights. Gift designations represent specific purposes for gifts, such as scholarship funds or building campaigns, enabling quick allocation of incoming donations to specific funds. Gift acknowledgment and tax receipt features simplify donor stewardship."],connections:[{planet:"analytics",desc:"Giving analytics and advancement dashboards"}]}
  ],
  dataFlow:["Graduate transitions to alumni status on person record","Alumni engagement activities are tracked and scored","Fundraising campaigns target segmented alumni populations","Gifts and pledges are recorded and acknowledged","Volunteer activities are coordinated and recognized"],
  connections:[{planet:"records",desc:"Alumni status tracked on person records"},{planet:"financials",desc:"Gift funds connect to institutional finance"},{planet:"agentforce",desc:"Alumni engagement agent manages outreach"},{planet:"experience",desc:"Alumni portal for giving and volunteering"},{planet:"analytics",desc:"Advancement dashboards and giving reports"}]
},

appointments: {
  packages: ['educationcloud'],
  name: "Appointments",
  icon: "\u{1F4C5}",
  color: "#14b8a6",
  description: "Provides centralized self-service appointment scheduling for advising, tutoring, financial aid counseling, and administrative meetings. Appointments manages staff availability calendars, walk-in waitlists, virtual meeting links, and appointment follow-up workflows. Students can book appointments through the portal based on department, topic, and available time slots.",
  components: [
    {id:"appointment-scheduling",name:"Appointment Scheduling",icon:"\u{1F4C5}",desc:"Enables students to book appointments with staff members based on department, service type, and available time slots. Education Cloud provides a central self-service system powered by Salesforce Scheduler where learners can view staff availability, schedule appointments, and if the virtual appointments feature is configured, join sessions virtually.",tags:["ServiceAppointment"],docs:["Education Cloud provides a central self-service system for managing appointments. Learners have visibility over staff availability in any department based on configured location and appointment channels. They can view and schedule appointments, and if the virtual appointments feature is set up, they can join virtually. Staff can also schedule appointments on behalf of learners from their records.","Salesforce Scheduler must be enabled for Education Cloud to support appointment management. The scheduler handles in-person, phone, and virtual appointment channels. Counselors, coaches, advisors, and other support staff can schedule and manage appointments with students in just a few clicks, with confirmation notifications including meeting details and calendar invitations.","Unifying all departments on a single scheduling tool increases learners' ability to use all of your institution's services. The Student Success portal includes My Appointments components where learners can view past and upcoming appointments. When a user clicks Schedule Appointment, the workflow to create an appointment appears as a popup directly within the portal."],connections:[{planet:"enrollment",desc:"Advising appointments precede course registration"},{planet:"success",desc:"Advising sessions support student success"}]},
    {id:"staff-availability",name:"Staff Availability",icon:"\u{1F464}",desc:"Manages staff calendars, service territories, and availability windows for appointment scheduling. Each staff member is configured as a service resource with skills, working hours, and service territory assignments. Service territories organize resources by department such as academic advising, financial aid, registrar, and student health services.",tags:["ServiceResource","ServiceTerritory"],docs:["Service resources represent staff members who are available for student appointments. Each resource has defined working hours, skills, and service territory assignments that determine which appointment types they can fulfill and when they are available. Capacity settings control concurrent appointment limits, and blocked time prevents scheduling during meetings or preparation periods.","Service territories define departments, offices, or locations where appointments are offered. They organize staff resources and appointment availability by functional area, enabling students to browse available slots by department and topic. The operating hours configuration on each territory determines when appointments can be scheduled.","External sharing settings for service resources should be set to Public Read Only to allow Experience Cloud site users to see staff availability. This enables the self-service appointment booking experience where learners can browse available time slots and select the most convenient option."],connections:[]},
    {id:"waitlist-management",name:"Waitlist & Walk-ins",icon:"\u{23F3}",desc:"Supports walk-in appointment flows with waitlist management and estimated wait times. Students can join a waitlist through the portal or by scanning a QR code at a physical location. The waitlist displays current position, estimated wait time, and staff member assignment. Notifications alert students when their turn approaches.",tags:["ServiceAppointment"],docs:["Walk-in appointment management complements the scheduled appointment system by accommodating students who need immediate assistance. The waitlist feature integrates with the same service territory and service resource configuration used for scheduled appointments, ensuring consistent capacity management across both channels.","Students can check appointment status including scheduled, checked in, completed, and no show through the portal. The system tracks appointment types including advising, tutoring, financial aid, and administrative meetings, with each appointment referencing both the student's person account and the assigned service territory and resource."],connections:[]},
    {id:"virtual-appointments",name:"Virtual Appointments",icon:"\u{1F4F9}",desc:"Extends appointment scheduling with video conferencing integration for remote advising, tutoring, and counseling sessions. Video Calls is an optional feature that can be enabled in Education Cloud to support virtual meeting links in appointment confirmations. Multi-channel support allows students to connect via video, phone, or chat based on the appointment type and student preference.",tags:["ServiceAppointment"],docs:["Virtual appointments are enabled by turning on the Video Calls feature in Education Cloud setup. Once enabled, virtual appointments automatically generate meeting links and embed them in confirmation notifications. This extends the standard Salesforce Scheduler appointment experience with remote meeting capabilities.","The learner portal supports appointment management on mobile devices, allowing students to schedule appointments and join virtual sessions on the go. The mobile-responsive design ensures the scheduling interface, appointment details, and virtual meeting links work seamlessly across smartphones and tablets."],connections:[{planet:"mentoring",desc:"Mentoring sessions use appointment scheduling"}]}
  ],
  dataFlow:["Staff configures availability and service territories","Student browses available slots by department and topic","Appointment is booked with confirmation and calendar invite","Walk-in students join the waitlist with estimated wait time","Virtual meeting link is generated for remote appointments"],
  connections:[{planet:"enrollment",desc:"Advising required before registration"},{planet:"records",desc:"Appointments reference student person records"},{planet:"success",desc:"Advising appointments support student success"},{planet:"mentoring",desc:"Mentoring sessions use appointment scheduling"}]
},

analytics: {
  packages: ['educationcloud'],
  name: "Education Analytics",
  icon: "\u{1F4CA}",
  color: "#f97316",
  description: "Delivers institutional insights through CRM Analytics dashboards covering recruitment yield, enrollment trends, retention rates, student success metrics, and financial health. Education Analytics provides pre-built dashboard templates for directors, recruiters, admissions officers, and advisors, each tailored to their decision-making needs. Custom report building enables institutions to create ad-hoc analyses specific to their reporting requirements.",
  components: [
    {id:"director-insights",name:"Director Insights",icon:"\u{1F3E2}",desc:"A multi-page dashboard providing institutional leadership with a comprehensive view of key performance indicators across recruitment, enrollment, retention, and graduation outcomes. Education Analytics provides pre-built dashboard templates for directors, recruiters, reviewers, admissions officers, and advisors, each tailored to their decision-making needs and installed through the CRM Analytics for Education setup.",tags:[],docs:["Education Analytics works seamlessly with existing Education Cloud features, enabling institutions to improve processes and learner metrics. The dashboards and institutional key performance indicators provide insights into recruitment, admissions, learner engagement, and student success. The system uses CRM Analytics with custom education-specific recipes and data connections.","Setting up Education Analytics requires enabling all Education Cloud dependent features, configuring the CRM Analytics permission sets, and installing the analytics app. The installation can take some time, and institutions can schedule regular data refreshes to ensure dashboards use the latest data. Manual refreshes are also available through the Analytics Studio data manager.","The Director Console for Student Success allows directors to create programs and benefits, assign advisors, view analytics dashboards for student success, view institutional KPIs, and more. The Director Console for Recruitment and Admissions shows admissions and recruitment analytics with the ability to create actionable lists and assign them to staff."],connections:[]},
    {id:"recruitment-analytics",name:"Recruitment Analytics",icon:"\u{1F4C8}",desc:"Tracks recruitment funnel metrics including inquiry volume, event attendance, application submission rates, and yield percentages by channel, territory, and counselor. The Admissions Console includes an Education Analytics Dashboard component showing Recruitment and Admissions Insights with application volume, review status, admission efficiency, and applications ready for decision.",tags:[],docs:["The Recruitment and Admissions Insights dashboard is embedded in the Admissions Console home page, providing admissions officers with at-a-glance visibility into the health of the admissions pipeline. Directors can track progress toward goals with a variety of KPI reports from their own console, which includes recruitment analytics, actionable lists, and staff assignment tools.","Prospect Engagement Score uses CRM Analytics to predict the likelihood of a prospective learner enrolling based on their current engagement level. This scoring framework helps the admissions team identify which prospects are most likely interested, enabling focused outreach that improves admission rates. The scoring template configuration is created within CRM Analytics using the Prospect Engagement Score type."],connections:[{planet:"recruitment",desc:"Recruitment funnel data feeds analytics"}]},
    {id:"student-success-metrics",name:"Student Success Metrics",icon:"\u{1F3C6}",desc:"Monitors retention, persistence, GPA distribution, credit accumulation, and graduation rates across student populations. The Advisor Console shows analytics dashboards for student success, advisor insights and KPIs, and care plan management. Einstein Academic Insights uses Data Cloud to provide predictive analytics on student performance.",tags:[],docs:["The Advisor Console in the Student Success app provides advisors with the ability to create and assign care plans, create alerts, view analytics dashboards for student success, view advisor insights and KPIs, and more. This home page is available out-of-the-box with Education Cloud and requires no additional setup to get started with student success monitoring.","Einstein Academic Insights, available as an optional feature, uses Data Cloud to generate current term and course offering participant insights. This feature requires the Agentforce for Education add-on license and provides predictive analytics that help advisors identify students who may need additional support before academic performance declines."],connections:[{planet:"success",desc:"Success tracking data powers analytics"}]},
    {id:"financial-analytics",name:"Financial Analytics",icon:"\u{1F4B0}",desc:"Provides visibility into tuition revenue, financial aid distribution, receivables aging, and payment plan utilization. Fundraising analytics track gift and donor trends with rollups, showing metrics related to donor giving and gift designations at a glance in the Fundraising Philanthropy and Partnerships app.",tags:[],docs:["Education Analytics dashboards aggregate financial data including tuition revenue, financial aid distribution, and enrollment-driven revenue projections. The analytics app includes recipes that process data from across Education Cloud domains to produce financial KPIs visible to directors and administrators. Revenue forecasting models use admissions pipeline data to project future enrollment-driven revenue.","Gift and donor trend rollups provide metrics related to donor giving and gift designations at a glance within the Fundraising Philanthropy and Partnerships app. Aid effectiveness analysis shows how different aid packaging strategies affect enrollment yield and net tuition revenue, enabling data-driven decisions about financial aid allocation."],connections:[{planet:"financials",desc:"Financial data feeds revenue dashboards"}]}
  ],
  dataFlow:["Data from recruitment, enrollment, success, and financial systems flows into analytics","Pre-built dashboards aggregate metrics into role-specific views","Directors review institutional KPIs and trend indicators","Department heads drill into program-level and cohort-level detail","Custom reports address ad-hoc institutional research questions"],
  connections:[{planet:"recruitment",desc:"Recruitment funnel dashboards"},{planet:"financials",desc:"Revenue and financial aid analytics"},{planet:"alumni",desc:"Advancement and giving dashboards"},{planet:"agentforce",desc:"Agent performance monitoring"}]
},

agentforce: {
  packages: ['educationcloud'],
  name: "Agentforce",
  icon: "\u{1F916}",
  color: "#a855f7",
  description: "Deploys AI-powered agents across the student lifecycle to automate communication, answer questions, and surface actionable insights. Agentforce for Education Cloud includes specialized agents for recruitment outreach, admissions Q&A, academic advising, financial aid guidance, and alumni engagement. Each agent is configured with education-specific topics, guardrails, and institutional knowledge.",
  components: [
    {id:"recruitment-agent",name:"Recruitment Agent",icon:"\u{1F4E3}",desc:"Automates personalized outreach to prospective students through email, SMS, and chat channels. The Student Recruitment Agent can answer questions about your school, programs, and admissions processes based on knowledge articles, and can help students apply to your school. It includes topics for Admissions and Enrollments FAQ, Admissions Application, Campus Tours Registration, and Request for Information.",tags:[],docs:["The Student Recruitment Agent includes four topics: Admissions and Enrollments FAQ uses knowledge articles to answer questions, Admissions Application creates applications for students, Campus Tours Visits and Events Registration assists with event sign-ups, and Request for Information creates academic interest records when prospects request recruiter contact. The agent can be deployed for both authenticated and unauthenticated users.","Knowledge articles ground the agent's responses and should align with four areas: learning programs, support programs, application processes, and campus and support information. The Answer Questions with Knowledge action is considered a public action, so institutions must ensure knowledge articles do not contain non-public information. The more information an article contains, the better the agent performs.","The agent supports both authenticated users through an Agentforce Employee Agent template and unauthenticated users through an Agentforce Service Agent template. For unauthenticated users, several flows must be cloned and configured to run in System Context Without Sharing. An escalation topic can be set up to redirect unanswered conversations to human representatives."],connections:[{planet:"recruitment",desc:"Automates recruitment outreach sequences"}]},
    {id:"admissions-agent",name:"Admissions Agent",icon:"\u{1F4CB}",desc:"Provides real-time application status updates and answers common admissions questions through conversational AI. The Student Recruitment Agent's Admissions and Enrollments FAQ topic answers questions based on knowledge articles about learning programs, support programs, application processes, and campus information. The Create Inquiry action captures cases for questions that require personal attention.",tags:[],docs:["The Admissions and Enrollments FAQ topic uses the Answer Questions with Knowledge action to find information in institutional knowledge articles. The agent can also retrieve learning program data to provide context-aware responses about specific programs. For questions that cannot be answered by the agent, an escalation topic redirects unanswered conversations to human representatives.","The Create Inquiry action creates a case, an educational information request, and an academic interest record when a prospective student, parent, or counselor raises a question that the agent cannot answer. This ensures that every inquiry is captured and routed to the appropriate staff member, even when the agent does not have sufficient information to respond directly."],connections:[{planet:"admissions",desc:"Answers applicant questions about their application"}]},
    {id:"success-agent",name:"Student Success Agent",icon:"\u{1F31F}",desc:"Assists students with academic planning, course selection, and career exploration through personalized conversations. Student Advising Topics in Agentforce help advisors summarize advising cases, answer questions about campus resources and policies, and suggest next-best actions. The Student Goals Agent provides SMART goal recommendations based on student profiles, preferences, and assessment insights.",tags:[],docs:["Student Advising Topics in Agentforce includes the Student Advising and Campus Engagement topic with three standard actions: Summarize Advising Case for quickly understanding a learner's case, Find Advising Cases for locating relevant cases, and Find Campus Resources for answering questions about facilities, services, activities, clubs, programs, and action plans. The agent uses knowledge articles for policy guidance and Einstein search retrievers for campus resource discovery.","The Student Goals Agent helps students get specific, measurable, achievable, relevant, and time-bound goal recommendations with AI-powered guidance. The Self Serve Student Goals topic empowers students directly, while the Advising Assist Student Goals topic helps advisors support students. Both topics include Suggest Student Goals, Create Goal, and Find Campus Resources actions.","Course Search in Agentforce helps students and advisors discover the right courses by answering questions about course requirements and degree planning information. The agent uses Data Cloud's Einstein Search capability to find courses that best suit students' interests, schedules, and degree program requirements without requiring appointments with advisors, especially useful during registration peak seasons."],connections:[{planet:"success",desc:"AI advising surfaces at-risk students"}]},
    {id:"financials-agent",name:"Student Financials Agent",icon:"\u{1F4B0}",desc:"Answers questions about account balances, fee breakdowns, payment due dates, and financial aid status. The Student Financials Agent includes a Student Fee Management topic that provides detailed fee breakdowns and explanations for specific academic terms, and a Student Account Management topic that provides total fee balances given specific attendance dates.",tags:[],docs:["The Student Financials Agent includes two topics: Student Fee Management provides detailed fee breakdowns and fee explanations for specific academic terms using Query Records, Get Record Details, Get Fee Details, and Get Fee Breakdown actions. The topic answers questions about fee amounts, fee descriptions, and optional fee types, using context from previous results to streamline explanations.","The Student Account Management topic provides total fee balances given specific attendance dates using the Get Account Balance action. It also provides fee breakdowns and details about account history. The agent supports both authenticated and unauthenticated students and can be added to Experience Cloud site portals.","Setting up the Student Financials Agent requires enabling Student Financial Account Management, configuring the necessary permission sets including Salesforce Pricing Runtime User and Education Cloud Student Financials for Experience Cloud Access, and setting field-level security for the Order Details Identifier field on the Academic Order object. The agent leverages generative AI and follows the Einstein Trust Layer for data security."],connections:[{planet:"financials",desc:"Handles billing and aid inquiries"}]},
    {id:"alumni-agent",name:"Alumni Agent",icon:"\u{1F3C5}",desc:"Engages alumni through personalized communication about giving opportunities, events, and volunteer activities. Alumni Engagement Metrics combines Data 360 calculated insights with Einstein generative AI prompt responses to provide comprehensive engagement summaries. The Engagement Visualization Panel can be added to alumni record pages to show engagement data and AI-generated narratives.",tags:[],docs:["Alumni Engagement Metrics uses sample prompts for the Engagement Visualization prompt template type to generate narrative summaries of alumni engagement. Four summarization categories are available: Overall Alumni Engagements for a high-level activity summary, Events and Activities for experiential engagement, Personal Engagement for meaningful communications, and Meaningful Impact for volunteerism contributions.","Each summarization prompt instructs the AI to analyze engagement data and produce a single paragraph not exceeding 300 characters, presented in the tone of an executive summary. The prompts enforce equal treatment of all individuals regardless of socioeconomic status, background, or other characteristics, and default to an unknown option when insufficient information is available. If no engagement data exists, a standard response indicates that data will be summarized when available."],connections:[{planet:"alumni",desc:"Manages alumni outreach and engagement"}]}
  ],
  dataFlow:["Agent is configured with education-specific topics and guardrails","Student or prospect initiates conversation through portal or messaging","Agent accesses relevant records to provide personalized responses","Complex inquiries are escalated to human staff with full context","Agent performance metrics feed into analytics dashboards"],
  connections:[{planet:"recruitment",desc:"Recruitment outreach automation"},{planet:"admissions",desc:"Application status Q&A"},{planet:"success",desc:"At-risk student identification"},{planet:"financials",desc:"Financial aid guidance"},{planet:"alumni",desc:"Alumni engagement automation"},{planet:"analytics",desc:"Agent usage metrics and dashboards"}]
},

experience: {
  packages: ['educationcloud'],
  name: "Experience Cloud",
  icon: "\u{1F310}",
  color: "#64748b",
  description: "Powers learner-facing self-service portals for application tracking, course registration, financial account management, and alumni community engagement. Experience Cloud provides pre-built portal components designed for higher education workflows, with responsive designs that work across desktop and mobile devices. Permission-based content visibility ensures students, applicants, and alumni each see only the information relevant to their role.",
  components: [
    {id:"student-portal",name:"Student Portal",icon:"\u{1F393}",desc:"A self-service hub where enrolled students access their academic records, register for courses, view grades, and manage their personal information. Lightning Web Components for Student Success bring self-service capabilities including viewing success teams and advisors, scheduling appointments, enrolling in support programs, managing care plans and tasks, and setting SMART career and life goals.",tags:[],docs:["The Education Portal template in Experience Builder provides education-specific components for building a learner-facing self-service site. Students can view their success team and assigned advisors, view advisor details and post questions, schedule and manage appointments, enroll into support programs and take assessments, view care plans, goals, and benefits, and manage tasks and action plans.","The learner portal is supported on mobile devices, allowing learners to view details of their care plans and success teams and schedule appointments with advisors on the go. The portal's responsive design ensures all functionality works across smartphones and tablets, with touch-friendly navigation and key actions designed for on-the-go convenience.","Permission-based content visibility ensures students, applicants, and alumni each see only the information relevant to their role. Audiences in Experience Builder allow institutions to create separate views for different user types, and component variations can be assigned based on user profile, enabling a personalized experience for each constituent group."],docUrl:"https://help.salesforce.com/s/articleView?id=sfdo.ec_set_up_an_education_portal.htm&language=en_US",connections:[{planet:"enrollment",desc:"Course registration through the portal"},{planet:"financials",desc:"Financial account access and payments"}]},
    {id:"applicant-portal",name:"Applicant Portal",icon:"\u{1F4CB}",desc:"Provides prospective and active applicants with a dedicated workspace for managing their application. The Education Portal template includes education-specific components for building a comprehensive applicant experience. Applicants can upload documents, complete supplemental forms, track application status, view document checklist completion, and receive decision notifications.",tags:[],docs:["The Education Portal template provides a starting point for building an applicant-facing self-service site. The portal collects information from prospective students and records it in Salesforce. Audiences in Experience Builder create separate views for different user types, enabling applicants to see their own application data, document checklists, and decision notifications while restricting access to other students' information.","Third-party applicants such as parents, guardians, or agents can submit applications on behalf of students through the portal. Sharing sets control what data each user type can access, with separate configurations for self-applicants and third-party submitters. The portal supports both authenticated and unauthenticated access patterns, with guest access for browsing program information and authenticated access for submitting applications."],connections:[{planet:"admissions",desc:"Application tracking and document submission"}]},
    {id:"alumni-portal",name:"Alumni Portal",icon:"\u{1F3C5}",desc:"An online community for graduates to stay connected with their institution, update career information, explore giving opportunities, and register for alumni events. The portal features an Alumni Profile component for sharing education and professional experience, and an Alumni Directory using Person Public Profile for search and connection with fellow graduates.",tags:[],docs:["Education Cloud provides Lightning components for creating an alumni community where graduates can connect with each other. The Alumni Profile component allows users to share information about their education and professional experience, with data sourced from the Person Education and Person Employment objects. The Person Public Profile component powers the alumni directory where users can search for and connect with one another.","Person Public Profile records are created and maintained using Data Processing Engine and flows that run on a configurable schedule. The process resolves duplicate person public profile and person public profile preference set records automatically. By default the flow runs weekly, but institutions can configure it to run daily to keep directory information current.","Alumni users need a Customer Community Plus license with the Education Cloud for Experience Cloud Access permission set. Sharing sets control access to accounts, person academic credentials, and program enrollments, ensuring alumni can see their own data and the public profiles of other graduates while maintaining appropriate privacy controls."],connections:[{planet:"alumni",desc:"Alumni community and giving portal"}]},
    {id:"mobile-experience",name:"Mobile Experience",icon:"\u{1F4F1}",desc:"Responsive design ensures all portal functionality works seamlessly across smartphones and tablets. The learner portal is supported on mobile devices, allowing learners to view details of their care plans and success teams, schedule appointments with advisors on the go, and manage tasks and action plans from any device.",tags:[],docs:["The Education Portal template in Experience Builder creates responsive sites that automatically adapt to different screen sizes. Mobile-optimized navigation and touch-friendly form inputs provide a native-like experience through the mobile browser. Students can access their personalized dashboard, view alerts, check appointment schedules, and interact with AI agents from their mobile devices.","AI agents including the Student Recruitment Agent, Student Goals Agent, and Student Financials Agent can be connected to Experience Cloud sites through messaging channels, enabling mobile-accessible conversational interactions. Students can ask questions about programs, fees, goals, and campus resources from their smartphones, receiving immediate AI-powered responses."],connections:[]}
  ],
  dataFlow:["Portal is configured with role-based page layouts and permissions","Student, applicant, or alumni authenticates and accesses personalized dashboard","Self-service actions trigger backend processes in Education Cloud","Status updates and notifications are pushed back to the portal","Mobile-responsive design ensures access across all devices"],
  connections:[{planet:"recruitment",desc:"Prospect inquiry and event portal"},{planet:"admissions",desc:"Application tracking portal"},{planet:"financials",desc:"Financial self-service portal"},{planet:"alumni",desc:"Alumni community portal"}]
},

data360: {
  packages: ['educationcloud'],
  name: "Data 360",
  icon: "\u{1F5C3}",
  color: "#06b6d4",
  description: "Consolidates student data from disparate legacy systems into a unified, deduplicated view using Salesforce Data 360 capabilities. Data 360 handles identity resolution across multiple source systems, standardizes data formats, and creates unified individual records that eliminate duplicate student entries. This is especially critical for institutions migrating from legacy student information systems where the same student may exist in multiple databases.",
  components: [
    {id:"data-consolidation",name:"Data Consolidation",icon:"\u{1F4E5}",desc:"Ingests student data from legacy student information systems, admissions platforms, and external databases into Education Cloud. Data 360 provides a central place to connect and prepare data from multiple sources, then harmonize the data into a unified learner profile that supports strategic decisions, automation, AI grounding, and customized learner experiences.",tags:["DataStream"],docs:["Educational data comes from multiple institutional systems: student information systems containing profile information, course registrations, fee payments, attendance records, and grades; learning management systems with login credentials, usage patterns, interactions, and assessments; and enterprise resource planning systems with financial records, tuition, financial aid, billing, and financial holds. Institutions also use data on housing, dining, event registration, and many other campus services.","The Education data kit packages Data 360 components including data streams and calculated insights, and helps deploy them in your org. The kit provides prebuilt mappings to key Education Cloud data model objects in six bundles: Education Cloud, Academic Operations, Alumni Engagement, Fundraising, Recruiting and Admissions, and Student Success. Each bundle maps to the specific data model objects relevant to that domain.","There are various prebuilt connectors to bring external data into Data 360, including Ingestion API, direct data source configuration, MuleSoft Anypoint Connector for Salesforce Data Cloud, and standard CRM data streams. After connecting a source, Data 360 accesses it so that you can create mapping sets between the objects and fields within it and the Data 360 data model objects."],connections:[]},
    {id:"identity-resolution",name:"Identity Resolution",icon:"\u{1F50D}",desc:"Detects and resolves duplicate student records across source systems using configurable matching rules. The Education data kit contains an identity resolution ruleset with match and reconciliation rules that link multiple sources of data into a unified profile. Confidence scoring ranks match quality, and resolution workflows present potential duplicates to staff for review and merge decisions.",tags:["IdentityResolutionRuleset","MatchRule"],docs:["The Education data kit includes an Alumni Identity Resolution Ruleset that defines matching rules for linking multiple sources of data into a unified profile. Match rules evaluate combinations of identifying fields such as name, date of birth, email, and student ID using exact, fuzzy, or phonetic comparison methods, each with a configurable importance weight that determines its contribution to the overall confidence score.","Auto-merge thresholds determine the confidence score above which records merge automatically, while review thresholds flag records for manual review by staff. This two-tier approach ensures high-confidence matches are resolved immediately while borderline cases receive human oversight, balancing efficiency with accuracy in the deduplication process.","To use calculated insights that contain the unified individual in the Engagement Visualization component, institutions must create a Contact data stream and map it for the identity resolution process. The semantic data model organizes Education Cloud data into a single, reusable model that calculates metrics consistently across Tableau Next components, Agents, and Marketing Cloud Growth campaigns."],connections:[{planet:"records",desc:"Resolved identities create unified person records"}]},
    {id:"unified-records",name:"Unified Records",icon:"\u{1F464}",desc:"Creates a single, authoritative record for each individual by merging the best data from multiple sources. Unified individual records apply survivorship rules that determine which source provides the most accurate value for each field. The unified learner profile supports making strategic decisions, automating tasks at scale, grounding AI in trusted data, and creating customized experiences for each learner.",tags:["UnifiedIndividual"],docs:["The Education data kit provides calculated insights out-of-the-box to help understand learner behavior. The Alumni Engagement bundle includes Comprehensive Engagements, Comprehensive with Unified Individual, Philanthropic Status, and Status of Giving insights. The Student Success bundle includes a Student Course Percentage Calculator. These insights can be activated and scheduled to publish on a regular cadence.","The Engagement Visualization Panel component shows Data 360 calculated insights related to an individual and Einstein generative AI prompt responses. It can be configured to show only calculated insights, only prompt responses, or a combination of both. The component supports any data stream, data model object, or calculated insight related to an individual, unified individual, or unified individual link.","A semantic data model can be created to organize Education Cloud data into a single, reusable model that calculates metrics consistently across Tableau Next components, Agents, and Marketing Cloud Growth campaigns. This layer gathers all data into a unified, comprehensive structure that improves the reliability of reports and dashboards, strengthens AI agent intelligence, and powers targeted marketing campaigns."],connections:[{planet:"records",desc:"Unified records feed into person accounts"}]},
    {id:"data-mapping",name:"Data Mapping & Standards",icon:"\u{1F5FA}",desc:"Establishes field-level mappings between external source system schemas and the Education Cloud data model. After importing education data into Data 360, you map the data to the required data model objects before using it for segmentation, activation, analytics, or any other operation. Education-specific data model objects cover credentials, interests, sessions, enrollments, and more.",tags:["DataStream"],docs:["After connecting a data source, Data 360 accesses it so that you can create mapping sets between the objects and fields within the source and the Education Cloud data model objects. The Education data kit provides prebuilt mappings to key data model objects in six bundles covering Education Cloud, Academic Operations, Alumni Engagement, Fundraising, Recruiting and Admissions, and Student Success.","The semantic data model organizes Education Cloud data into a single, reusable model that calculates metrics consistently across Tableau Next components, Agents, and Marketing Cloud Growth campaigns. Installing the Education Cloud semantic data model from the data kit provides a standardized interpretation layer that improves the reliability of reports and the intelligence of AI agent interactions."],connections:[]}
  ],
  dataFlow:["Source systems are connected via data streams with extraction schedules","Raw data is mapped and transformed to the Education Cloud schema","Identity resolution detects duplicates across source systems","Matched records are merged into unified individual records","Unified data feeds all Education Cloud domains through person accounts"],
  connections:[{planet:"records",desc:"Identity resolution unifies student person records"}]
}

};
